boot.artifact:
// 先挂可见容器再动态加载大模块,避免冷缓存时 1.7s 探针误判空白
['assets/diagram-js.css','assets/dmn-js-shared.css','assets/dmn-js-drd.css','assets/dmn-js-decision-table.css','assets/dmn-font/css/dmn.css'].forEach(p => { const l = document.createElement('link'); l.rel = 'stylesheet'; l.href = 'https://cdn.jsdelivr.net/npm/dmn-js@17.10.0/dist/' + p; document.head.appendChild(l); });
const container = document.getElementById('dmn'); container.style.cssText = 'height:400px;overflow:auto';
const status = document.createElement('div'); status.textContent = 'Loading decision model…'; container.appendChild(status);
const { default: DmnViewer } = await import('https://cdn.jsdelivr.net/npm/dmn-js@17.10.0/+esm');
const viewer = new DmnViewer({ container });
await viewer.importXML(data.dmnXml); status.remove();

